namespace QuickCode.Demo.Infrastructure.Web;

public static class ServiceCollectionExtensions
{
    private const string ElasticSearchUriKey = "Logging:ElasticConfiguration:Uri";
    private const string DefaultSwaggerUrl = "https://www.quickcode.net";

    public static IServiceCollection AddQuickCodeSwaggerGen(this IServiceCollection services,IConfiguration configuration, Action<SwaggerGenOptions>? configureOptions=null, string tokenType = "Bearer")
    {
        services.AddSwaggerGen(options =>
        {
            options.CustomSchemaIds(type => type.FullName);
            options.EnableAnnotations();
            options.SwaggerDoc("v1", new OpenApiInfo()
            {
                Version = "v1",
                Title = $"{configuration["Swagger:Title"]} ({Assembly.GetExecutingAssembly().GetName().Version})",
                TermsOfService = ToUri(configuration["Swagger:TermsOfService"]),
                Contact = new OpenApiContact
                {
                    Name = "Üzeyir Apaydın",
                    Url = ToUri(configuration["Swagger:Contact"])
                },
                License = new OpenApiLicense
                {
                    Name = "QuickCode.Net License",
                    Url = ToUri(configuration["Swagger:License"])
                }
            });

            options.CustomOperationIds(e =>
            {
                try
                {
                    var controllerName = e.ActionDescriptor.RouteValues["controller"];
                    var actionName = e.ActionDescriptor.RouteValues["action"];
                    var operationId = $"{controllerName}{actionName}";
                    return operationId;
                }
                catch
                {
                    var relativePath = e.RelativePath!.Replace("/", "-")
                        .Replace("{", "-")
                        .Replace("}", "-");
                    var operationId = $"{relativePath}-{e.HttpMethod!.ToLowerInvariant()}".Replace("--", "-");
                    return operationId;
                }
            });
            
            switch (tokenType)
            {
                case "Bearer":
                    options.AddSecurityDefinition(tokenType, new OpenApiSecurityScheme
                    {
                        In = ParameterLocation.Header,
                        Description = "Please enter a valid token",
                        Name = "Authorization",
                        Type = SecuritySchemeType.Http,
                        BearerFormat = tokenType,
                        Scheme = tokenType
                    });

                    options.AddSecurityRequirement(new OpenApiSecurityRequirement
                    {
                        {
                            new OpenApiSecurityScheme
                            {
                                Reference = new OpenApiReference
                                {
                                    Type = ReferenceType.SecurityScheme,
                                    Id = tokenType
                                },
                            },
                            new List<string>() { }
                        }
                    });
                    break;
            }

            configureOptions?.Invoke(options);

            options.SchemaFilter<EnumSchemaFilter>();
        });

        return services;
    }

    public static IServiceCollection AddQuickCodeDbConnectionFactory(this IServiceCollection services)
    {
        services.AddSingleton<IDbConnectionFactory, DbConnectionFactory>();
        services.AddSingleton<QuickCodeSqlMigrationRunner>();
        services.AddSingleton<QuickCodeSeedDataRunner>();
        return services;
    }
    
    public static void AddLogger(this IServiceCollection services, IConfiguration configuration)
    {
        var excludingFilters = new Dictionary<string, List<string>>()
        {
            { "RequestPath", ["/hc"] }
        };

        var environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production";
        var loggerConfiguration = new LoggerConfiguration()
            .Enrich.FromLogContext()
            .Enrich.WithMachineName()
            .WriteTo.Debug()
            .WriteTo.Console()
            .Filter.ByExcluding(e =>
                excludingFilters.Keys.Any(filterKey =>
                    e.Properties.ContainsKey(filterKey) &&
                    excludingFilters[filterKey].Contains(((ScalarValue)e.Properties[filterKey]).Value!.ToString()!)))
            .ReadFrom.Configuration(configuration)
            .Enrich.WithProperty("Environment", environment);

        if (TryGetElasticConnectionString(configuration, out var elasticConnectionString))
        {
            loggerConfiguration = loggerConfiguration.WriteTo.Elasticsearch(
                CreateElasticSinkOptions(elasticConnectionString, configuration, environment));
        }

        var logger = loggerConfiguration.CreateLogger();
        Log.Logger = logger;
        if (!services.IsReadOnly)
        {
            services.AddSerilog(logger, dispose: true);
        }
    }

    private static Uri ToUri(string? value) =>
        string.IsNullOrWhiteSpace(value) ? new Uri(DefaultSwaggerUrl) : new Uri(value);

    private static bool TryGetElasticConnectionString(IConfiguration configuration, out string connectionString)
    {
        connectionString = Environment.GetEnvironmentVariable("ELASTIC_CONNECTION_STRING")
                           ?? configuration[ElasticSearchUriKey]
                           ?? string.Empty;
        return !string.IsNullOrWhiteSpace(connectionString);
    }

    private static ElasticsearchSinkOptions CreateElasticSinkOptions(
        string elasticConnectionString,
        IConfiguration configuration,
        string environment)
    {
        return new ElasticsearchSinkOptions(new Uri(elasticConnectionString))
        {
            AutoRegisterTemplate = true,
            IndexFormat =
                $"{configuration["Logging:ApiName"]}--{environment.ToLowerInvariant()
                    .Replace(".", "-")}--{DateTime.UtcNow:yyyy-MM-dd}"
        };
    }
